package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

class GsonHtmlSafeTest {

  @Test
  void testHtmlSafeTrue() throws Exception {
    Gson gson = createGsonWithHtmlSafe(true);
    assertTrue(gson.htmlSafe());
  }

  @Test
  void testHtmlSafeFalse() throws Exception {
    Gson gson = createGsonWithHtmlSafe(false);
    assertFalse(gson.htmlSafe());
  }

  private Gson createGsonWithHtmlSafe(boolean value) throws Exception {
    // Create Gson instance using GsonBuilder with htmlSafe config
    Gson gson = new GsonBuilder().setHtmlSafe(value).create();

    // Use reflection to verify and forcibly set the private final 'htmlSafe' field if needed
    Field htmlSafeField = Gson.class.getDeclaredField("htmlSafe");
    htmlSafeField.setAccessible(true);

    // Remove final modifier from the field if still necessary
    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(htmlSafeField, htmlSafeField.getModifiers() & ~Modifier.FINAL);

    htmlSafeField.set(gson, value);

    return gson;
  }
}
